void insert(Q, x) {
    push(S1, x);
}

void delete(Q) {
    if (stack-empty(S2)) then
        if (stack-empty(S1)) then {
            print("Q is empty");
            return;
        } else while (!(stack-empty(S1))) {
            push(S2, pop(S1));
        }
    pop(S2);
}

